{"name": "build_graph@dependency_graph/build_graph.py", "description": "DOCSTRING"}</s>{"name": "add_imports@dependency_graph/build_graph.py", "description": "DOCSTRING", "code": "def add_imports(root_node, imports, graph, repo_path):
    for imp in imports:
        if imp['type'] == 'import':
            # Handle 'import module' statements
            module_name = imp['module']
            module_path = resolve_module(module_name, repo_path)
            if module_path:
                imp_filename = os.path.relpath(module_path, repo_path)
                if graph.has_node(imp_filename):
                    graph.add_edge(root_node, imp_filename, type=EDGE_TYPE_IMPORTS, alias=imp['alias'])
        elif imp['type'] == 'from':
            # Handle 'from module import entity' statements
            module_name = imp['module']
            entities = imp['entities']

            if len(entities) == 1 and entities[0]['name'] == '*':
                # Handle 'from module import *' as 'import module' statement
                module_path = resolve_module(module_name, repo_path)
                if module_path:
                    imp_filename = os.path.relpath(module_path, repo_path)
                    if graph.has_node(imp_filename):
                        graph.add_edge(root_node, imp_filename, type=EDGE_TYPE_IMPORTS, alias=None)
                continue  # Skip further processing for 'import *'

            for entity in entities:
                entity_name, entity_alias = entity['name'], entity['alias']
                entity_module_name = f"{module_name}.{entity_name}"
                entity_module_path = resolve_module(entity_module_name, repo_path)
                if entity_module_path:
                    # Entity is a submodule
                    entity_filename = os.path.relpath(entity_module_path, repo_path)
                    if graph.has_node(entity_filename):
                        graph.add_edge(root_node, entity_filename, type=EDGE_TYPE_IMPORTS, alias=entity_alias)
                else:
                    # Entity might be an attribute inside the module
                    module_path = resolve_module(module_name, repo_path)
                    if module_path:
                        imp_filename = os.path.relpath(module_path, repo_path)
                        node = f"{imp_filename}:{entity_name}"
                        if graph.has_node(node):
                            graph.add_edge(root_node, node, type=EDGE_TYPE_IMPORTS, alias=entity_alias)
                        elif graph.has_node(imp_filename):
                            graph.add_edge(root_node, imp_filename, type=EDGE_TYPE_IMPORTS, alias=entity_alias)"}

{"name": "CodeFile@repo_index/repository.py", "description": "DOCSTRING"}</s>{"name": "Module@repo_index/codeblocks/module.py", "description": "DOCSTRING", "code": "class Module(CodeBlock):
    model_config = ConfigDict(arbitrary_types_allowed=True)

    file_path: str
    content: str
    spans_by_id: Dict[str, BlockSpan] = {}
    language: str | None = None
    parent: CodeBlock | None = None

    _graph: DiGraph = None  # TODO: Move to central CodeGraph

    def __init__(self, **data):
        data.setdefault('type', CodeBlockType.MODULE)
        super().__init__(**data)

    def find_span_by_id(self, span_id: str) -> Optional[BlockSpan]:
        return self.spans_by_id.get(span_id)

    def sum_tokens(self, span_ids: Optional[Set[str]] = None):
        tokens = self.tokens
        if span_ids:
            for span_id in span_ids:
                span = self.spans_by_id.get(span_id)
                if span:
                    tokens += span.tokens
            return tokens

        tokens += sum([child.sum_tokens() for child in self.children])
        return tokens

    def find_related_span_ids(self, span_id: str) -> Set[str]:
        related_span_ids = set()

        blocks = self.find_blocks_by_span_id(span_id)
        for block in blocks:
            # Find successors (outgoing relationships)
            successors = list(self._graph.successors(block.path_string()))
            for succ in successors:
                node_data = self._graph.nodes[succ]
                if 'block' in node_data:
                    span = node_data['block'].belongs_to_span
                    related_span_ids.add(span.span_id)

            # Find predecessors (incoming relationships)
            predecessors = list(self._graph.predecessors(block.path_string()))
            for pred in predecessors:
                node_data = self._graph.nodes[pred]
                if 'block' in node_data:
                    span = node_data['block'].belongs_to_span
                    related_span_ids.add(span.span_id)

            # Always add parent class initation span
            if (
                block.parent
                and block.parent.type == CodeBlockType.CLASS
                and block.belongs_to_span is not None
            ):
                related_span_ids.add(block.belongs_to_span.span_id)
                for class_child in block.parent.children:
                    if (
                        class_child.belongs_to_span
                        and class_child.belongs_to_span.span_type == SpanType.INITATION
                    ):
                        related_span_ids.add(class_child.belongs_to_span.span_id)

        # Always add module initation span
        for span in self.spans_by_id.values():
            if (
                span.block_type == CodeBlockType.MODULE
                and span.span_type == SpanType.INITATION
            ):
                related_span_ids.add(span.span_id)

        return related_span_ids"}

{"name": "auto_search_process@auto_search_main.py", "description": "DOCSTRING"}</s>{"name": "ResponseParser@util/actions/action_parser.py", "description": "DOCSTRING", "code": "class ResponseParser:
    def __init__(self):
        # Need pay attention to the item order in self.action_parsers
        # super().__init__()

        self.action_parsers = [
            CodeActActionParserFinish(),
            # CodeActActionParserCmdRun(),
            CodeActActionParserIPythonRunCell(),
            # CodeActActionParserAgentDelegate(),
        ]
        self.default_parser = CodeActActionParserMessage()

    def parse(self, response) -> Union[List[Action], Action]:
        # using tool calling
        if response.choices[0].message.tool_calls:
            try:
                actions = parse_tool_calls_to_actions(response)
                return actions
            except:
                logging.info("Un know tools")

        # using code to call tools
        action_str = self.parse_response(response)
        return self.parse_action(action_str)

    def parse_response(self, response) -> str:
        action = response.choices[0].message.content
        if action is None:
            return ''
        for lang in ['bash', 'ipython', 'browse']:
            if f'<execute_{lang}>' in action and f'</execute_{lang}' in action and f'</execute_{lang}>' not in action:
                action += '>'
            if f'<execute_{lang}>' in action and f'</execute_{lang}>' not in action:
                action += f'</execute_{lang}>'
        return action

    def parse_action(self, action_str: str) -> Union[List[Action], Action]:
        for action_parser in self.action_parsers:
            if action_parser.check_condition(action_str):
                return action_parser.parse(action_str)
        return self.default_parser.parse(action_str)"}

