{"name": "CodeIndex@repo_index/index/code_index.py", "description": "DOCSTRING"}</s>{"name": "count_tokens@repo_index/utils/tokenizer.py", "description": "DOCSTRING", "code": "def count_tokens(content: str, model: str = 'gpt-3.5-turbo') -> int:
    global _enc, _voyageai

    if model.startswith('voyage'):
        if _voyageai is None:
            voyageai_import_err = (
                '`voyageai` package not found, please run `pip install voyageai`'
            )
            try:
                import voyageai
            except ImportError:
                raise ImportError(voyageai_import_err)

            _voyageai = voyageai.Client()

        return _voyageai.count_tokens([content])

    if _enc is None:
        tiktoken_import_err = (
            '`tiktoken` package not found, please run `pip install tiktoken`'
        )
        try:
            import tiktoken
        except ImportError:
            raise ImportError(tiktoken_import_err)

        # set tokenizer cache temporarily
        should_revert = False
        if 'TIKTOKEN_CACHE_DIR' not in os.environ:
            should_revert = True
            os.environ['TIKTOKEN_CACHE_DIR'] = os.path.join(
                os.path.dirname(os.path.abspath(__file__)),
                '_static/tiktoken_cache',
            )

        _enc = tiktoken.encoding_for_model(model)

        if should_revert:
            del os.environ['TIKTOKEN_CACHE_DIR']

    return len(_enc.encode(content, allowed_special='all'))"}

{"name": "convert_non_fncall_messages_to_fncall_messages@util/runtime/fn_call_converter.py", "description": "Convert non-function calling messages back to function calling messages."}</s>{"name": "convert_from_multiple_tool_calls_to_single_tool_call_messages@util/runtime/fn_call_converter.py", "description": "Break one message with multiple tool calls into multiple messages.", "code": "def convert_from_multiple_tool_calls_to_single_tool_call_messages(
    messages: list[dict],
    ignore_final_tool_result: bool = False,
) -> list[dict]:
    """Break one message with multiple tool calls into multiple messages."""
    converted_messages = []

    pending_tool_calls: dict[str, dict] = {}
    for message in messages:
        role, content = message['role'], message['content']
        if role == 'assistant':
            if message.get('tool_calls') and len(message['tool_calls']) > 1:
                # handle multiple tool calls by breaking them into multiple messages
                for i, tool_call in enumerate(message['tool_calls']):
                    pending_tool_calls[tool_call['id']] = {
                        'role': 'assistant',
                        'content': content if i == 0 else '',
                        'tool_calls': [tool_call],
                    }
            else:
                converted_messages.append(message)
        elif role == 'tool':
            if message['tool_call_id'] in pending_tool_calls:
                # remove the tool call from the pending list
                _tool_call_message = pending_tool_calls.pop(message['tool_call_id'])
                converted_messages.append(_tool_call_message)
                # add the tool result
                converted_messages.append(message)
            else:
                assert (
                    len(pending_tool_calls) == 0
                ), f'Found pending tool calls but not found in pending list: {pending_tool_calls=}'
                converted_messages.append(message)
        else:
            assert (
                len(pending_tool_calls) == 0
            ), f'Found pending tool calls but not expect to handle it with role {role}: {pending_tool_calls=}, {message=}'
            converted_messages.append(message)

    if not ignore_final_tool_result and len(pending_tool_calls) > 0:
        raise FunctionCallConversionError(
            f'Found pending tool calls but no tool result: {pending_tool_calls=}'
        )
    return converted_messages"}

